import { useEffect } from 'react';

/**
 * Хук проверки на клик снаружи календаря. Общий хук для всех календарей.
 */
export const useOnOutsideCalendarClick = ({
	calendarElement,
	datepickerElement,
	disabled,
	onOutsideClick,
	rootElement,
}: {
	/** Элемент самого календаря */
	calendarElement: HTMLElement | null;
	/** Элемент дейтпикера (поля ввода к которому крепится календарь) */
	datepickerElement?: HTMLElement | null;
	/** Отключает проверку на клик */
	disabled?: boolean;
	/** Событие клика снаружи */
	onOutsideClick: () => void;
	/** Корневой элемент контейнера в котором отображается календарь */
	rootElement: HTMLElement | ShadowRoot;
}): void => {
	useEffect(() => {
		if (disabled) {
			return;
		}

		const handleOutsideClick = (event: Event): void => {
			const targetElement = event?.target as HTMLElement;

			const isOutsideClick = ![datepickerElement, calendarElement].some(
				element => element && element.contains(targetElement),
			);

			if (isOutsideClick && onOutsideClick) {
				onOutsideClick();
			}
		};

		const listenerContainer = rootElement || globalThis;

		listenerContainer.addEventListener('mousedown', handleOutsideClick);

		return () => listenerContainer.removeEventListener('mousedown', handleOutsideClick);
	}, [calendarElement, datepickerElement, disabled, onOutsideClick, rootElement]);
};
